// components/AboutMe.jsx
import Image from 'next/image';
import React, { useEffect, useState } from "react";
import profilePic from '../app/assets/media/profilepic.jpg'; // your uploaded image

export default function AboutMe() {
  const [years, setYears] = useState(0);
  const [projects, setProjects] = useState(0);

  useEffect(() => {
    // Counter animation for years
    let yearCount = 0;
    const yearInterval = setInterval(() => {
      if (yearCount < 2) {
        yearCount += 1;
        setYears(yearCount);
      } else {
        clearInterval(yearInterval);
      }
    }, 500); // speed in ms

    // Counter animation for projects
    let projectCount = 0;
    const projectInterval = setInterval(() => {
      if (projectCount < 15) {
        projectCount += 1;
        setProjects(projectCount);
      } else {
        clearInterval(projectInterval);
      }
    }, 100); // speed in ms

    return () => {
      clearInterval(yearInterval);
      clearInterval(projectInterval);
    };
  }, []);

  return (
    <section className="py-5 bg-dark text-light">
      <div className="container">
        <div className="text-center mb-5">
          <h2 className="fw-bold about-me-title">About Me</h2>
          <hr className="mx-auto my-3" style={{ width: '90px', borderTop: '6px solid #ff2e63' }} />
          <p>Get to know the person behind the code</p>
        </div>

        <div className="row align-items-center">
          {/* Text content */}
          <div className="col-lg-6 mb-4 mb-lg-0">
            <div className="about-desc">
              <p>
                I'm a passionate frontend developer with a love for creating beautiful,
                functional web experiences. My journey in web development started
                with curiosity and has evolved into a dedication to crafting digital
                solutions that make a difference.
              </p>
              <p>
                When I'm not coding, you'll find me exploring new technologies,
                contributing to open-source projects, or learning about the latest
                trends in web development. I believe in continuous learning and
                pushing the boundaries of what's possible on the web.
              </p>
              <p>
                My goal is to bridge the gap between design and development,
                creating seamless user experiences that are both visually stunning
                and highly functional.
              </p>
            </div>
            <div className="row gx-4 mt-4">
              <div className="col-lg-6 text-start">
                <h4 className="text-white">{years}+</h4>
                <p>Years Experience</p>
              </div>
              <div className="col-lg-6 text-end">
                <h4>{projects}+</h4>
                <p>Projects Completed</p>
              </div>
            </div>
          </div>

          {/* Image */}
          <div className="col-lg-6 text-center">
            <div className="profile-border" style={{ maxWidth: '350px', margin: '0 auto' }}>
              <Image
                src={profilePic}
                alt="Profile"
                width={350}
                height={450}
                className="img-fluid"
              />
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}